export default function Focus() {
  const people = [
    {
      label: "Truck drivers",
      riskRate: "4.75%",
      meanAge: "30.90",
      img: "/assets/truck-driver.png",
    },
    {
      label: "Dark Store Workers",
      riskRate: "2.36%",
      meanAge: "24.34",
      img: "/assets/store.png",
    },
    {
      label: "Delivery Partners",
      riskRate: "3.04%",
      meanAge: "27.94",
      img: "/assets/delivery.png",
    },
  ];

  return (
    <div style={{
      background: `radial-gradient(ellipse 70% 80% at 100% 50%, rgba(28,67,185,0.55) 0%, transparent 65%), #0d0d0d`,
      minHeight: "100vh",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      padding: "100px 64px",
    }}>
      {/* Title */}
      <h2 style={{
        fontFamily: "'Inter','Helvetica Neue',sans-serif",
        fontSize: "clamp(52px,7.5vw,110px)",
        fontWeight: 800, color: "white",
        margin: "0 0 56px", textAlign: "center", lineHeight: 1.05,
      }}>
        People in focus
      </h2>

      {/* Cards */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(3,1fr)",
        gap: 20, width: "100%", maxWidth: 1100,
      }}>
        {people.map((p, i) => (
          <div key={i} style={{
            background: "rgba(255,255,255,0.06)",
            border: "1px solid rgba(255,255,255,0.1)",
            borderRadius: 16, padding: "32px 28px 0",
            display: "flex", flexDirection: "column",
            position: "relative", overflow: "hidden",
            minHeight: 320,
          }}>
            {/* Label */}
            <div style={{
              color: "#e53e3e", fontSize: "clamp(14px,1.1vw,18px)",
              fontWeight: 700, marginBottom: 24,
              fontFamily: "'Inter',sans-serif",
            }}>{p.label}</div>

            {/* Risk Rate */}
            <div style={{
              color: "white", fontSize: "clamp(32px,3.5vw,52px)",
              fontWeight: 800, lineHeight: 1, fontFamily: "'Inter',sans-serif",
            }}>{p.riskRate}</div>
            <div style={{
              color: "rgba(255,255,255,0.65)", fontSize: 15,
              marginTop: 6, marginBottom: 28, fontFamily: "'Inter',sans-serif",
            }}>Risk Rate</div>

            {/* Mean Age */}
            <div style={{
              color: "rgba(255,255,255,0.65)", fontSize: 15,
              marginBottom: 6, fontFamily: "'Inter',sans-serif",
            }}>Mean Age</div>
            <div style={{
              color: "white", fontSize: "clamp(28px,3vw,46px)",
              fontWeight: 800, lineHeight: 1, fontFamily: "'Inter',sans-serif",
            }}>{p.meanAge}</div>
            <div style={{
              color: "rgba(255,255,255,0.65)", fontSize: 15,
              marginTop: 6, fontFamily: "'Inter',sans-serif",
            }}>years</div>

            {/* Worker image — bottom right */}
            <img
              src={p.img}
              alt={p.label}
              style={{
                position: "absolute", bottom: 0, right: 0,
                width: "45%", maxWidth: 160,
                objectFit: "contain", objectPosition: "bottom right",
              }}
            />
          </div>
        ))}
      </div>
    </div>
  );
}
